insert into storage.objects(bucket_id,name) values
('homework-originals','30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/page-original.png'),
('homework-processed','30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/page-processed.png'),
('homework-thumbnails','30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/page-thumbnail.png'),
('homework-processed','30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000002/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/foreign-processed.png'),
('homework-thumbnails','30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000002/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/foreign-thumbnail.png'),
('homework-originals','30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/53000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/other-assignment.png');

set local role authenticated;
select set_config('request.jwt.claims','{"sub":"20000000-0000-0000-0000-000000000001","role":"authenticated"}',true);

select throws_ok($$select * from public.start_or_resume_attempt_draft('6b000000-0000-0000-0000-000000000001')$$,'P0001','manual_part_already_submitted','returned manual submission locks draft attempts');
select throws_ok($$select * from public.submit_attempt('6b000000-0000-0000-0000-000000000001','{}','6d000000-0000-0000-0000-000000000002')$$,'P0001','manual_part_already_submitted','returned manual submission locks new automatic attempts');
select is((select status::text from public.homework_assignments where id='6b000000-0000-0000-0000-000000000001'),'returned','assignment remains returned');
select is((select count(*)::int from public.attempts where assignment_id='6b000000-0000-0000-0000-000000000001'),1,'automatic attempt count does not increase');
select is((select attempt_id from public.submit_attempt('6b000000-0000-0000-0000-000000000001','{}','6d000000-0000-0000-0000-000000000001')),'6c000000-0000-0000-0000-000000000001'::uuid,'old idempotency key returns the existing attempt');

select throws_ok($$select public.finalize_manual_submission('6e000000-0000-0000-0000-000000000002','[{"original_path":"30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/page-original.png","processed_path":"30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000002/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/foreign-processed.png","thumbnail_path":"30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/page-thumbnail.png","original_name":"page.png","mime_type":"image/png","size_bytes":1,"width":1,"height":1}]')$$,'P0001','invalid_path','foreign processed path is rejected');
select throws_ok($$select public.finalize_manual_submission('6e000000-0000-0000-0000-000000000002','[{"original_path":"30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/page-original.png","processed_path":"30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/page-processed.png","thumbnail_path":"30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000002/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/foreign-thumbnail.png","original_name":"page.png","mime_type":"image/png","size_bytes":1,"width":1,"height":1}]')$$,'P0001','invalid_path','foreign thumbnail path is rejected');
select throws_ok($$select public.finalize_manual_submission('6e000000-0000-0000-0000-000000000002','[{"original_path":"30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/53000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/other-assignment.png","processed_path":"30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/page-processed.png","thumbnail_path":"30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/page-thumbnail.png","original_name":"page.png","mime_type":"image/png","size_bytes":1,"width":1,"height":1}]')$$,'P0001','invalid_path','another assignment path is rejected');
select lives_ok($$select public.finalize_manual_submission('6e000000-0000-0000-0000-000000000002','[{"original_path":"30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/page-original.png","processed_path":"30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/page-processed.png","thumbnail_path":"30000000-0000-0000-0000-000000000001/10000000-0000-0000-0000-000000000001/20000000-0000-0000-0000-000000000001/6b000000-0000-0000-0000-000000000001/6f000000-0000-0000-0000-000000000002/page-thumbnail.png","original_name":"page.png","mime_type":"image/png","size_bytes":1,"width":1,"height":1}]')$$,'matching original, processed and thumbnail paths finalize successfully');

select * from finish();
rollback;
